// ESG-FILTER voor SmartESG (MKB-maakindustrie, VSME/CSRD/MVO)
const rssItems = items;
let sourceData = {};
try { sourceData = $('Loop RSS Sources').item.json; } catch(e) { sourceData = { Type: 'Nieuws' }; }

const backlogItems = $('Get Backlog (RSS dedupe)').all();
const existingUrls = backlogItems.map(i => i.json.URL);

// === GROENE LIJST (vertrouwde ESG/industrie domeinen) ===
const esgDomeinen = [
  'futureup.nl', 'mvonederland.nl', 'metaalunie.nl', 'deindustrie.online',
  'dnv.com', 'dnv.nl', 'group.bureauveritas.com', 'bureauveritas.com',
  'ecovadis.com', 'esgtoday.com', 'esgnow.eu', 'sustainalize.com',
  'rvo.nl', 'ser.nl', 'nen.nl',
  'fd.nl', 'mt.nl', 'sprout.nl', 'emerce.nl', 'mtsprout.nl',
  'klimaatakkoord.nl', 'groenebrief.nl', 'duurzaam-ondernemen.nl', 'duurzaamnieuws.nl',
  'sciencebasedtargets.org', 'ghgprotocol.org', 'efrag.org', 'unglobalcompact.org'
];

// === RODE LIJST (verboden onderwerpen) ===
const verbodenWoorden = [
  'tiktok','snapchat','gaming','crypto','bitcoin','nft',
  'voetbal','eredivisie','knvb','olympische','psv','ajax','feyenoord',
  'moord','overval','drugs','cocaine','kinderporno','verdachte','aangehouden',
  'knmi','code oranje','code geel','sneeuw','storm','onweer','gladheid',
  'tarot','horoscoop','sterrenbeeld','vacature','sollicitatie'
];

// === ESG-RELEVANTIE ZOEKTERMEN ===
const esgTermen = [
  'esg','csrd','vsme','mvo','duurzaamheidsrapportage','duurzaamheid','sustainability',
  'co2','co₂','klimaat','energietransitie','energieneutraal','net zero','klimaatdoelen',
  'scope 1','scope 2','scope 3','ghg','broeikasgas','emissies','footprint','lca','levenscyclus',
  'materialiteit','dubbele materialiteit','double materiality',
  'supply chain','toeleveringsketen','keten','due diligence','ketenverantwoordelijkheid',
  'mkb','maakindustrie','metaal','automotive','food','high-tech','industrie','productie',
  'iso 14001','iso 26000','sbti','sbtn','science based','taxonomie','taxonomy','sfdr','cba',
  'circulair','circulariteit','recycling','hergebruik','grondstof',
  'rapportage','jaarverslag','transparantie','vsme rapport',
  'efrag','europese commissie','klimaatwet','europese green deal','green deal',
  'rvo','ser','nen','metaalunie','ondernemers','bedrijfsleven',
  'audit','certificering','iso','assurance','verification',
  'innovatie','transitie','energie','besparing','efficiency','transformatie'
];

const nieuweItems = rssItems.filter(item => {
  const link = (item.json.link || item.json.url || '').toLowerCase();
  const title = (item.json.title || '').toLowerCase();
  const snippet = (item.json.contentSnippet || item.json.content || '').toLowerCase();
  const fullText = title + ' ' + snippet;

  if (existingUrls.includes(item.json.link)) return false;

  // Vertrouwde site? altijd laten passeren
  const isEsgSite = esgDomeinen.some(d => link.includes(d));
  if (isEsgSite) return true;

  // Verboden onderwerp? blocken
  const isVerboden = verbodenWoorden.some(w => fullText.includes(w));
  if (isVerboden) return false;

  // Anders: alleen door als er ESG-term in zit
  return esgTermen.some(term => fullText.includes(term));
});

return nieuweItems.map(item => {
  let samenvatting = item.json.contentSnippet || item.json.content || 'Geen samenvatting';
  if (samenvatting.length > 2000) samenvatting = samenvatting.substring(0, 2000) + '... (ingekort)';
  return {
    json: {
      URL: item.json.link || item.json.url,
      Titel: item.json.title,
      Samenvatting: samenvatting,
      Type: sourceData.Type || 'Nieuws',
      Bron_Site: sourceData.Bron || 'RSS',
      Bron_Taal: sourceData.Taal || 'NL',
      Datum_Toegevoegd: new Date().toISOString().split('T')[0]
    }
  };
});

const raw = $json.output || '[]';
const clean = raw.replace(/```json|```/g, '').trim();

let articles = [];
try { articles = JSON.parse(clean); } catch(e) { return []; }
if (!Array.isArray(articles)) return [];

const sourceData = $('Loop Scrape Sources').item.json;
const existingUrls = $('Get Backlog (Scrape dedupe)').all().map(i => i.json.URL);

return articles
  .filter(a => a && a.url && !existingUrls.includes(a.url))
  .map(a => ({
    json: {
      URL: a.url,
      Titel: a.titel || 'Onbekend',
      Samenvatting: (a.samenvatting || '').substring(0, 2000),
      Type: sourceData.Type || 'Scrape',
      Bron_Site: sourceData.Site_Naam,
      Bron_Taal: sourceData.Taal || 'NL',
      Datum_Toegevoegd: new Date().toISOString().split('T')[0]
    }
  }));

// Pak het NIEUWSTE backlog-item (laatst toegevoegd)
let items = $input.all();
if (items.length === 0) return [];

items.sort((a, b) => {
  const dA = new Date(a.json.Datum_Toegevoegd || 0);
  const dB = new Date(b.json.Datum_Toegevoegd || 0);
  return dB - dA;
});

const nieuwste = items[0];
return {
  json: {
    Zoekterm: nieuwste.json.Titel,
    Nieuws_Context: nieuwste.json.Samenvatting,
    Bron_URL: nieuwste.json.URL,
    Bron_Site: nieuwste.json.Bron_Site,
    Bron_Taal: nieuwste.json.Bron_Taal,
    Type: nieuwste.json.Type
  }
};

// HTTP HEAD overschrijft $json met response - herstel origineel
const orig = $('Pick Newest').first().json;
return { json: orig };

const raw = $json.output || '{}';
const clean = raw.replace(/```json|```/g, '').trim();
try { return { json: JSON.parse(clean) }; }
catch(e) { return { json: { error: 'Parse failed', raw_output: raw } }; }

function parseDate(s){ if(!s) return 0; return new Date(s).getTime(); }

const sorted = items.sort((a,b) => parseDate(a.json.Laatst_Gebruikt) - parseDate(b.json.Laatst_Gebruikt));

const formatted = sorted.map(i => {
  const t = i.json.Zoekterm;
  const lu = i.json.Laatst_Gebruikt || 'Nooit';
  return `- ${t} | (Laatst gebruikt: ${lu})`;
}).join('\n');

return [{ json: { keyword_list: formatted } }];

return items.map(item => {
  const raw = item.json.output || '{}';
  const clean = raw.replace(/```json|```/g, '').trim();
  try { return { json: JSON.parse(clean) }; }
  catch(e) { return { json: { relevant: false, error: 'Parse failed' } }; }
});

// Author Router - alternerend Tom of Bas op basis van dag van het jaar
// Voice/voorbeelden/config worden uit de Authors-sheet gelezen via de 'Get Authors' node
const now = new Date();
const start = new Date(now.getFullYear(), 0, 0);
const diff = now - start;
const dayOfYear = Math.floor(diff / (1000 * 60 * 60 * 24));
const authorKey = dayOfYear % 2 === 0 ? 'Tom' : 'Bas';

// Pak de juiste rij uit de Authors-sheet
const authorRows = $('Get Authors').all();
const authorRow = authorRows.find(r => (r.json.author || '').trim() === authorKey);

if (!authorRow) {
  throw new Error(`Author '${authorKey}' niet gevonden in Authors sheet. Check de 'author' kolom (waarden: Tom, Bas).`);
}

const cfg = authorRow.json;

return {
  json: {
    author: cfg.author,
    author_naam: cfg.naam,
    author_rol: cfg.rol,
    author_voice: cfg.voice,
    author_voorbeelden: cfg.voorbeelden,
    unipile_account_id: cfg.unipile_account_id,
    review_email: cfg.review_email,
    thema: $('Parse Thema JSON').first().json.gekozen_thema,
    invalshoek: $('Parse Thema JSON').first().json.invalshoek,
    bron_url: $('Parse Thema JSON').first().json.bron_url,
    bron_titel: $('Pick Newest').first().json.Zoekterm,
    bron_site: $('Pick Newest').first().json.Bron_Site
  }
};

const raw = $json.output || '{}';
const clean = raw.replace(/```json|```/g, '').trim();
let parsed = {};
try { parsed = JSON.parse(clean); }
catch(e) { parsed = { post_tekst: raw, haakje: '', hashtags: [] }; }

return { json: { ...$('Author Router (Tom/Bas)').first().json, ...parsed } };

// Format Post Data voor Posts_Review sheet
const data = $json;
const timestamp = new Date().toISOString();
const postId = 'post-' + timestamp.replace(/[:.]/g, '-').substring(0, 19) + '-' + (data.author || 'unknown').toLowerCase();

return {
  json: {
    id: postId,
    datum: timestamp.split('T')[0],
    author: data.author,
    author_naam: data.author_naam,
    thema: data.thema,
    invalshoek: data.invalshoek || '',
    bron_titel: data.bron_titel,
    bron_url: data.bron_url,
    bron_site: data.bron_site,
    post_tekst: data.post_tekst,
    haakje: data.haakje || '',
    hashtags: Array.isArray(data.hashtags) ? data.hashtags.join(' ') : '',
    status: 'pending',
    feedback: '',
    linkedin_post_id: '',
    unipile_account_id: data.unipile_account_id,
    review_email: data.review_email,
    generated_at: timestamp
  }
};
